INSERT INTO peliculas (titulo, canal, msg_id, enlace) VALUES ('Se anunció una adaptación a anime para la novela historica "Oedo Fire Slayer - The Legend of Phoenix".', '@Neoanimes', 9830, 'https://t.me/Neoanimes/9830'),('El Blu-ray/DVD de las películas recopilatorias "Bocchi the Rock! Re:/Re:Re:" vendió un estimado de 1.026 copias en su segunda semana, acumulando un total de 15.161 copias desde su lanzamiento.', '@Neoanimes', 9829, 'https://t.me/Neoanimes/9829'),('El Blu-ray/DVD de la película "Boku no Hero Academia: You''re Next" vendió un total de 20.519 copias en su primera semana.', '@Neoanimes', 9828, 'https://t.me/Neoanimes/9828'),('El Blu-ray/DVD de la película "Wonderful Precure!: Dokidoki Game no Sekai de Daibouken!" ha vendido un total de 7.835 copias en su primera semana.', '@Neoanimes', 9827, 'https://t.me/Neoanimes/9827'),('El Blu-ray de la película "Uma Musume: Pretty Derby - Shin Jidai no Tobira" vendió un total de 27.169 copias en su primera semana.', '@Neoanimes', 9826, 'https://t.me/Neoanimes/9826'),('El segundo volumen de Blu-ray/DVD del anime "Blue Box" vendió un total de 1.173 copias en su primera semana.', '@Neoanimes', 9825, 'https://t.me/Neoanimes/9825'),('Ilustracion Bonus de la tercera temporada del anime "Arifureta Shokugyou de Sekai Saikyou" por comprar todos los Blu-ray BOX en la tienda Toranoana.', '@Neoanimes', 9824, 'https://t.me/Neoanimes/9824'),('Se ha anunciado que el manga "Ninja to Gokudou" recibirá una adaptación a anime de TV.', '@Neoanimes', 9823, 'https://t.me/Neoanimes/9823'),('Ilustraciones Bonus del anime "Medalist" por comprar volúmenes de Blu-ray/DVD en tiendas especificas.', '@Neoanimes', 9820, 'https://t.me/Neoanimes/9820'),('Nuevas ilustraciones del anime "Kimi no Koto ga Daidaidaidaidaisuki na 100-nin no Kanojo" para una colaboración con cafe&bar MENU que se realizará en Marzo.', '@Neoanimes', 9819, 'https://t.me/Neoanimes/9819'),('Nuevo Visual del anime "Seishun Buta Yarou" para una exposición que se realizará el 25 de Abril.', '@Neoanimes', 9818, 'https://t.me/Neoanimes/9818'),('Se anunció que el anime "Mobile Suit Gundam: GQuuuuuuX" comenzará a emitirse a partir del próximo 8 de Abril.', '@Neoanimes', 9817, 'https://t.me/Neoanimes/9817'),('Nuevo Key Visual para el anime "Uma Musume Cinderella Gray".', '@Neoanimes', 9816, 'https://t.me/Neoanimes/9816'),('Nuevo Key Visual del anime "Uchuujin Muumuu".', '@Neoanimes', 9815, 'https://t.me/Neoanimes/9815'),('Nuevo Visual mensual del anime en emisión "Kusuriya no Hitorigoto".', '@Neoanimes', 9814, 'https://t.me/Neoanimes/9814'),('Se ha revelado un nuevo Key Visual para el anime "Rock wa Lady no Tashinami deshite".', '@Neoanimes', 9813, 'https://t.me/Neoanimes/9813'),('Nuevo Key Visual del anime original "Maebashi Witches".', '@Neoanimes', 9812, 'https://t.me/Neoanimes/9812'),('📅No se ha revelado fecha de emisión, ni más información.', '@Neoanimes', 8763, 'https://t.me/Neoanimes/8763'),('Se reveló la portada para el quinto volumen de Blu-ray/DVD del anime "Monogatari Series: Off & Monster Season".', '@Neoanimes', 9810, 'https://t.me/Neoanimes/9810'),('Se reveló un Key Visual actualizado del anime "Isekai Mokushiroku Mynoghra: Hametsu no Bunmei de Hajimeru Sekai Seifuku".', '@Neoanimes', 9809, 'https://t.me/Neoanimes/9809'),('Nuevo Key Visual del anime "Yuusha Party wo Tsuihou sareta Shiromadoushi, S-Rank Boukensha ni Hirowareru: Kono Shiromadoushi ga Kikakugai Sugiru".', '@Neoanimes', 9808, 'https://t.me/Neoanimes/9808'),('Se reveló la portada para el tercer volumen de Blu-ray BOX de la tercera temporada del anime "Arifureta Shokugyou de Sekai Saikyou", que se lanzará el próximo 9 de Abril.', '@Neoanimes', 9807, 'https://t.me/Neoanimes/9807'),('La cuenta oficial del anime "Kimetsu no Yaiba" anunció que la fecha de estreno de la película "Mugen Jou-hen" se revelará el próximo 1 de Marzo.', '@Neoanimes', 9806, 'https://t.me/Neoanimes/9806'),('Amagami-san Chi no Enmusubi » Episodio 17 Audio Latino 🇲🇽', '@Neoanimes', 9804, 'https://t.me